-- Expand the provinces table to cover all Philippine provinces (+ NCR) with their
-- complete official list of component cities/municipalities. For provinces that
-- already exist, only region/cities/sort_order are refreshed -- any multiplier the
-- admin already customized is left untouched.

ON CONFLICT ("name") DO UPDATE SET
  "region" = EXCLUDED."region",
  "cities" = EXCLUDED."cities",
  "sort_order" = EXCLUDED."sort_order";
